+      }
+      return p.then(() => initStorePromise(allData));
+    }
+
+    function initStorePromise(data) {
+      return new Promise(resolve => featureStore.init(data, () => {
+        inited = true;
+        resolve();
+      }));
+    }
+
+    function parseData(data) {
