+                // send progress
+                this.postMessage(new UiMessage(UI.BUNDLE_PROGRESS, {
+                    progress: i,
+                    response,
+                }));
+            }
+
+            this.progress++;
+        }
+        return this.hasBundle ? responses : responses[0];
+    }
