+        dispatch({
+            type: DashboardActionTypes.DASHBOARD_SET_RECOMMENDATIONS,
+            recommendations,
+            timestamp,
+        });
+
+        logger.info(`dashboardActions.updateRecommendations: updated recommendations at ${timestamp}`);
+
+        return recommendations;
+    };
+}

